module RefModule(
 	input clk,
 	input cl,
  input up,
  input w,
  input [31:0] d,
 	output reg [31:0] q
     );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
 	begin
   	if (cl == 1)
   		q<=0;
   	else if(w == 1)
      q<=d;
    else
   		if(up == 1)
   			q<=q+1;
 	end


 endmodule
